parameters.pythonCode:
import json
import re

ai_output = _input.first().json["output"]

json_match = re.search(r"```json\s*(.*?)\s*```", ai_output, re.DOTALL)
if json_match:
    json_str = json_match.group(1)
else:
    json_match = re.search(r"\{.*\}", ai_output, re.DOTALL)
    json_str = json_match.group(0) if json_match else ai_output

parsed = json.loads(json_str)

return [{
    "json": {
        "imagePrompt": parsed["ImagePrompt"],
        "textPrompt": parsed["TextPrompt"],
        "generatedTitle": parsed.get("GeneratedTitle", "Untitled")
    }
}]
